\n-- ==========================================\n-- TABELA: api_requests\n-- ==========================================\n\nDROP TABLE IF EXISTS api_requests CASCADE;\n\nCREATE TABLE api_requests (\n    id SERIAL NOT NULL,\n    method VARCHAR(10) NOT NULL,\n    endpoint VARCHAR(100) NOT NULL,\n    data JSONB NOT NULL,\n    created_at TIMESTAMP DEFAULT now(),\n    server_id VARCHAR(100)\n);\n\nALTER TABLE api_requests ADD PRIMARY KEY (id);\n\n-- Dados para api_requests\nINSERT INTO api_requests (id, method, endpoint, data, created_at, server_id) VALUES (1, 'GET', 'api_data_get', '{"data":{"test":"true","action":"buy","symbol":"BTCUSDT"},"method":"GET","headers":{"user-agent":"Mozilla/5.0 (Windows NT; Windows NT 10.0; pt-BR) WindowsPowerShell/5.1.26100.4652"},"server_id":"028eaa711309e0cbbc8a94a656dd4887","timestamp":"2025-07-26T11:08:49.060Z"}', '"2025-07-26T14:08:49.106Z"', '028eaa711309e0cbbc8a94a656dd4887');\nINSERT INTO api_requests (id, method, endpoint, data, created_at, server_id) VALUES (2, 'POST', 'api_data_post', '{"body":{"test":true,"price":3200,"action":"sell","symbol":"ETHUSDT"},"query":{},"method":"POST","headers":{"user-agent":"Mozilla/5.0 (Windows NT; Windows NT 10.0; pt-BR) WindowsPowerShell/5.1.26100.4652","content-type":"application/json"},"server_id":"028eaa711309e0cbbc8a94a656dd4887","timestamp":"2025-07-26T11:08:56.118Z"}', '"2025-07-26T14:08:56.121Z"', '028eaa711309e0cbbc8a94a656dd4887');\n\n\n-- ==========================================\n-- TABELA: raw_webhook\n-- ==========================================\n\nDROP TABLE IF EXISTS raw_webhook CASCADE;\n\nCREATE TABLE raw_webhook (\n    id SERIAL NOT NULL,\n    source VARCHAR(50) NOT NULL,\n    payload JSONB NOT NULL,\n    status VARCHAR(20) DEFAULT 'received'::character varying,\n    created_at TIMESTAMP DEFAULT now(),\n    processed_at TIMESTAMP,\n    server_id VARCHAR(100),\n    version VARCHAR(50),\n    error_message TEXT,\n    retry_count INTEGER DEFAULT 0\n);\n\nALTER TABLE raw_webhook ADD PRIMARY KEY (id);\n\n-- Índices para raw_webhook\nCREATE INDEX idx_raw_webhook_source ON public.raw_webhook USING btree (source);\nCREATE INDEX idx_raw_webhook_created_at ON public.raw_webhook USING btree (created_at);\nCREATE INDEX idx_raw_webhook_status ON public.raw_webhook USING btree (status);\nCREATE INDEX idx_raw_webhook_payload_gin ON public.raw_webhook USING gin (payload);\n\n-- Dados para raw_webhook\nINSERT INTO raw_webhook (id, source, payload, status, created_at, processed_at, server_id, version, error_message, retry_count) VALUES (1, 'test', '{"test":true,"timestamp":"2025-07-26T11:27:56.743Z"}', 'received', '"2025-07-26T14:27:56.708Z"', NULL, NULL, NULL, NULL, 0);\n\n\n-- ==========================================\n-- TABELA: system_config\n-- ==========================================\n\nDROP TABLE IF EXISTS system_config CASCADE;\n\nCREATE TABLE system_config (\n    id SERIAL NOT NULL,\n    config_key VARCHAR(100) NOT NULL,\n    config_value TEXT,\n    description TEXT,\n    created_at TIMESTAMP DEFAULT now(),\n    updated_at TIMESTAMP DEFAULT now()\n);\n\nALTER TABLE system_config ADD PRIMARY KEY (id);\n\n-- Índices para system_config\nCREATE UNIQUE INDEX system_config_config_key_key ON public.system_config USING btree (config_key);\n\n-- Dados para system_config\nINSERT INTO system_config (id, config_key, config_value, description, created_at, updated_at) VALUES (1, 'migration_version', '2.0.0', 'Versão da migração atual', '"2025-07-26T14:27:55.787Z"', '"2025-07-26T14:27:55.787Z"');\nINSERT INTO system_config (id, config_key, config_value, description, created_at, updated_at) VALUES (2, 'migration_date', '2025-07-26T11:27:55.821Z', 'Data da última migração', '"2025-07-26T14:27:55.787Z"', '"2025-07-26T14:27:55.787Z"');\nINSERT INTO system_config (id, config_key, config_value, description, created_at, updated_at) VALUES (3, 'project_name', 'coinbitclub-market-bot-v3', 'Nome do projeto Railway', '"2025-07-26T14:27:55.787Z"', '"2025-07-26T14:27:55.787Z"');\nINSERT INTO system_config (id, config_key, config_value, description, created_at, updated_at) VALUES (4, 'api_version', '1.0.0', 'Versão da API', '"2025-07-26T14:27:55.787Z"', '"2025-07-26T14:27:55.787Z"');\nINSERT INTO system_config (id, config_key, config_value, description, created_at, updated_at) VALUES (5, 'webhook_enabled', 'true', 'Habilitar recepção de webhooks', '"2025-07-26T14:27:55.787Z"', '"2025-07-26T14:27:55.787Z"');\nINSERT INTO system_config (id, config_key, config_value, description, created_at, updated_at) VALUES (6, 'max_webhook_retries', '3', 'Máximo de tentativas para processar webhooks', '"2025-07-26T14:27:55.787Z"', '"2025-07-26T14:27:55.787Z"');\nINSERT INTO system_config (id, config_key, config_value, description, created_at, updated_at) VALUES (7, 'rate_limit_requests', '1000', 'Limite de requisições por hora', '"2025-07-26T14:27:55.787Z"', '"2025-07-26T14:27:55.787Z"');\nINSERT INTO system_config (id, config_key, config_value, description, created_at, updated_at) VALUES (8, 'rate_limit_window', '3600', 'Janela de tempo para rate limit (segundos)', '"2025-07-26T14:27:55.787Z"', '"2025-07-26T14:27:55.787Z"');\n\n\n-- ==========================================\n-- TABELA: tradingview_signals\n-- ==========================================\n\nDROP TABLE IF EXISTS tradingview_signals CASCADE;\n\nCREATE TABLE tradingview_signals (\n    id SERIAL NOT NULL,\n    symbol VARCHAR(20) NOT NULL,\n    action VARCHAR(10) NOT NULL,\n    price DECIMAL(15,8),\n    strategy VARCHAR(100),\n    timestamp TIMESTAMP DEFAULT now(),\n    processed BOOLEAN DEFAULT false,\n    metadata JSONB,\n    webhook_id INTEGER\n);\n\nALTER TABLE tradingview_signals ADD PRIMARY KEY (id);\n\n-- Índices para tradingview_signals\nCREATE INDEX idx_tradingview_signals_symbol ON public.tradingview_signals USING btree (symbol);\nCREATE INDEX idx_tradingview_signals_action ON public.tradingview_signals USING btree (action);\nCREATE INDEX idx_tradingview_signals_timestamp ON public.tradingview_signals USING btree ("timestamp");\nCREATE INDEX idx_tradingview_signals_processed ON public.tradingview_signals USING btree (processed);\n\n\n-- ==========================================\n-- TABELA: transactions\n-- ==========================================\n\nDROP TABLE IF EXISTS transactions CASCADE;\n\nCREATE TABLE transactions (\n    id SERIAL NOT NULL,\n    signal_id INTEGER,\n    transaction_type VARCHAR(20) NOT NULL,\n    symbol VARCHAR(20) NOT NULL,\n    amount DECIMAL(15,8),\n    price DECIMAL(15,8),\n    status VARCHAR(20) DEFAULT 'pending'::character varying,\n    exchange_response JSONB,\n    created_at TIMESTAMP DEFAULT now(),\n    executed_at TIMESTAMP\n);\n\nALTER TABLE transactions ADD PRIMARY KEY (id);\n\n\n-- ==========================================\n-- TABELA: users\n-- ==========================================\n\nDROP TABLE IF EXISTS users CASCADE;\n\nCREATE TABLE users (\n    id SERIAL NOT NULL,\n    email VARCHAR(255) NOT NULL,\n    name VARCHAR(255),\n    role VARCHAR(50) DEFAULT 'user'::character varying,\n    status VARCHAR(20) DEFAULT 'active'::character varying,\n    api_key VARCHAR(255),\n    last_login TIMESTAMP,\n    created_at TIMESTAMP DEFAULT now(),\n    updated_at TIMESTAMP DEFAULT now()\n);\n\nALTER TABLE users ADD PRIMARY KEY (id);\n\n-- Índices para users\nCREATE UNIQUE INDEX users_email_key ON public.users USING btree (email);\nCREATE UNIQUE INDEX users_api_key_key ON public.users USING btree (api_key);\n\n-- Dados para users\nINSERT INTO users (id, email, name, role, status, api_key, last_login, created_at, updated_at) VALUES (1, 'admin@coinbitclub.com', 'Admin', 'admin', 'active', 'cbm_1753529276026_q2lby0zdtd', NULL, '"2025-07-26T14:27:55.991Z"', '"2025-07-26T14:27:55.991Z"');\n\n-- ==========================================\n-- FUNÇÕES\n-- ==========================================\n\n-- Função: update_updated_at_column\n
      BEGIN
        NEW.updated_at = NOW();
        RETURN NEW;
      END;
